create table stocks_sorties (id int primary key, stocks_id int NOT NULL, localisation_sortie_id int, localisation_entree_id int, notes varchar(150), date_sortie date NOT NULL, heure_sortie time NOT NULL, nom_entreprise_client varchar(50), quartier_entreprise_client varchar(50), ville_entreprise_client varchar(50), region_etat_entreprise_client varchar(50), reference varchar(50), designation varchar(50) NOT NULL, nom_departement_produit varchar(50) NOT NULL, categorie varchar(50) NOT NULL, quantite_sortie double NOT NULL, nom_entreprise_fournisseur varchar(50), prix_unitaire double, montant_tva double, montant_total_vente double,  localisation_sortie varchar(256) NOT NULL, localisation_entree varchar(50) NOT NULL, nom_recepteur varchar(50) NOT NULL, date_peremption varchar(50), nom_magasinier varchar(50) NOT NULL, nom_utilisateur_magasinier varchar(50) NOT NULL, reference_recu_sortie varchar(50), marge_beneficiaire double, localisation_stock varchar(50), historique_stock varchar(6500), historique_stock_actif tinyint, is_service boolean NOT NULL, unite_de_mesure_de_Vente int(3));
